/* globals createDemoTabs, oneDark, ClassicEditor */

createDemoTabs( '#source-editing-enhanced-themes-demo', [
	{
		EditorCreator: ClassicEditor,
		contentElementId: '#editor-light',
		getToolbar: editor => editor.ui.view.toolbar,
		onConfig: config => {
			config.toolbar.items = [
				'undo', 'redo',
				'|', 'sourceEditingEnhanced',
				'|', 'heading',
				'|', 'bold', 'italic', 'underline', 'strikethrough', 'subscript', 'superscript', 'code',
				'-', 'link', 'insertImage', 'insertTable', 'blockQuote', 'mediaEmbed', 'codeBlock',
				'|', 'alignment',
				'|', 'bulletedList', 'numberedList', 'todoList', 'outdent', 'indent'
			];
		},
		onChange( { attachTourBalloon } ) {
			attachTourBalloon();
		}
	},
	{
		EditorCreator: ClassicEditor,
		contentElementId: '#editor-dark',
		getToolbar: editor => editor.ui.view.toolbar,
		onConfig: config => {
			config.ckbox.forceDemoLabel = false;
			config.sourceEditingEnhanced = {
				theme: oneDark
			};
			config.toolbar.items = [
				'undo', 'redo',
				'|', 'sourceEditingEnhanced',
				'|', 'heading',
				'|', 'bold', 'italic', 'underline', 'strikethrough', 'subscript', 'superscript', 'code',
				'-', 'link', 'insertImage', 'insertTable', 'blockQuote', 'mediaEmbed', 'codeBlock',
				'|', 'alignment',
				'|', 'bulletedList', 'numberedList', 'todoList', 'outdent', 'indent'
			];
		},
		onChange( { attachTourBalloon } ) {
			attachTourBalloon();
		}
	}
] );
